// API version switcher — renders a small <select> dropdown at the top of
// any page whose URL is under /api/, letting users jump between stable,
// dev, and the previously-released v0.0.x-alpha.N snapshots.
//
// Scoped to /api/ pages ONLY (not the whole site) because mkdocs-material's
// built-in version provider is theme-global and we don't want versioning
// on /articles/, /analyzers/, /getting-started/, etc.
//
// Data source: fetches <site>/api/versions.json at runtime. That file is
// generated by scripts/generate-versioned-api-docs.sh during release.yml
// and preserved on gh-pages across ci.yml runs via peaceiris keep_files.
// If the fetch 404s (bootstrap period before the first post-switcher
// release, or misconfigured path), the switcher silently doesn't render.
//
// Caveat: when the user switches from stable/<pkg>/<type>/ to
// v0.0.2-alpha.N/, we naively reuse the same <pkg>/<type>/ tail. If that
// page didn't exist in the older version (new type, renamed class), the
// user lands on a 404. Mitigation: the dropdown always includes a "root"
// navigation implicit in the version-only path, so users can back out.
(function () {
    'use strict';

    const ALREADY_RENDERED_ID = 'needlr-api-version-switcher';
    const API_SEGMENT = '/api/';

    function init() {
        const path = window.location.pathname;
        const apiIdx = path.indexOf(API_SEGMENT);
        if (apiIdx === -1) return;                          // not an /api/ page
        if (document.getElementById(ALREADY_RENDERED_ID)) return; // already placed

        // apiRoot ends with "/api/" (includes trailing slash)
        const apiRoot = path.slice(0, apiIdx + API_SEGMENT.length);
        const versionsUrl = apiRoot + 'versions.json';

        fetch(versionsUrl, { cache: 'no-cache' })
            .then(function (r) { return r.ok ? r.json() : null; })
            .then(function (data) {
                if (!data || !Array.isArray(data.entries) || data.entries.length === 0) return;
                renderSwitcher(data, apiRoot, path);
            })
            .catch(function () { /* silent no-op on fetch failure */ });
    }

    function renderSwitcher(data, apiRoot, currentPath) {
        const article = document.querySelector('article.md-content__inner') ||
                        document.querySelector('.md-content__inner') ||
                        document.querySelector('main');
        if (!article) return;

        // Figure out which path segment represents the current version:
        //   /needlr/api/stable/... -> "stable"
        //   /needlr/api/dev/...    -> "dev"
        //   /needlr/api/v0.0.2-alpha.27/... -> "v0.0.2-alpha.27"
        //   /needlr/api/           -> "" (catalog page; no version selected)
        const afterApi = currentPath.slice(apiRoot.length);
        const firstSlash = afterApi.indexOf('/');
        const currentSeg = firstSlash === -1 ? afterApi : afterApi.slice(0, firstSlash);
        const tail = firstSlash === -1 ? '' : afterApi.slice(firstSlash + 1);

        const container = document.createElement('div');
        container.id = ALREADY_RENDERED_ID;
        container.className = 'admonition note';
        container.style.cssText = 'margin-top: 0; margin-bottom: 1em; padding: 0.6em 0.8em; display: flex; align-items: center; gap: 0.75em; flex-wrap: wrap;';

        const label = document.createElement('label');
        label.textContent = 'API version:';
        label.style.cssText = 'font-weight: 600; font-size: 0.85em; margin: 0;';
        label.htmlFor = 'needlr-api-version-select';

        const select = document.createElement('select');
        select.id = 'needlr-api-version-select';
        select.style.cssText = 'padding: 0.25em 0.5em; font-size: 0.85em; background: var(--md-default-bg-color); color: var(--md-default-fg-color); border: 1px solid var(--md-default-fg-color--lightest); border-radius: 3px; min-width: 14em;';

        for (let i = 0; i < data.entries.length; i++) {
            const e = data.entries[i];
            if (e.separator) {
                const sep = document.createElement('option');
                sep.disabled = true;
                sep.textContent = '──────────';
                select.appendChild(sep);
                continue;
            }
            const opt = document.createElement('option');
            opt.value = e.path;
            opt.textContent = e.label;
            if (e.path === currentSeg) opt.selected = true;
            select.appendChild(opt);
        }

        select.addEventListener('change', function () {
            const target = apiRoot + this.value + '/' + tail;
            window.location.href = target;
        });

        container.appendChild(label);
        container.appendChild(select);

        // Inject as the first child of the article body, above the heading.
        article.insertBefore(container, article.firstChild);
    }

    // mkdocs-material swaps content on client-side navigation via instant
    // loading; listen for both initial load and subsequent navigation.
    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', init);
    } else {
        init();
    }
    // Re-run on mkdocs-material's instant-nav hook if available
    if (typeof document$ !== 'undefined' && document$ && typeof document$.subscribe === 'function') {
        document$.subscribe(init);
    }
})();
